python3 -c "
import json, urllib.request

all_data = []
for page in [1, 2]:
    url = f'https://api.worldbank.org/v2/country/all/indicator/NY.GNS.ICTR.ZS?date=2001:2010&format=json&per_page=2640&page={page}'
    try:
        req = urllib.request.Request(url, headers={'User-Agent': 'Mozilla/5.0'})
        with urllib.request.urlopen(req, timeout=60) as resp:
            raw = json.loads(resp.read().decode())
            if len(raw) > 1:
                all_data.extend(raw[1])
                print(f'Page {page}: got {len(raw[1])} records')
    except Exception as e:
        print(f'Page {page} error: {e}')

print(f'Total records: {len(all_data)}')

# Build country-year data - filter out non-countries (regions, aggregates)
# Non-country ISO3 codes are typically 3-letter codes that don't match standard ISO 3166
# Let's collect all unique countries
countries = {}
for rec in all_data:
    iso3 = rec['countryiso3code']
    name = rec['country']['value']
    year = rec['date']
    val = rec['value']
    if iso3 not in countries:
        countries[iso3] = {'name': name, 'years': {}}
    if val is not None:
        countries[iso3]['years'][year] = val

# Known aggregate/region codes to exclude
aggregates = {'AFE', 'AFW', 'ARB', 'CSS', 'CEB', 'EAR', 'EAS', 'EAP', 'TEA', 'EMU', 'ECS', 'TEC', 
              'EUU', 'FCS', 'HPC', 'HIC', 'IBD', 'IBT', 'IDA', 'IDB', 'IDX', 'INX', 'LAC', 'TLA',
              'LCN', 'LDC', 'LIC', 'LMC', 'LMY', 'LTE', 'MEA', 'TMN', 'MIC', 'MNA', 'NAC', 'OED',
              'OSS', 'PSS', 'PST', 'SST', 'SAS', 'TSA', 'SSA', 'TSS', 'SSF', 'SFM', 'UMC', 'WLD',
              'EAR', 'HIC', 'INX', 'PRE', 'PRT', 'SVK'}

# Find countries with >35% for ALL 10 years
results = []
required_years = [str(y) for y in range(2001, 2011)]

for iso3, info in countries.items():
    if iso3 in aggregates:
        continue
    name = info['name']
    years = info['years']

    # Check if all 10 years have data AND all > 35%
    all_above = True
    for y in required_years:
        if y not in years:
            all_above = False
            break
        if years[y] <= 35:
            all_above = False
            break

    if all_above:
        min_val = min(years[y] for y in required_years)
        results.append((name, iso3, min_val))

results.sort(key=lambda x: x[0])
print(f'\nCountries with gross savings > 35% of GDP for ALL years 2001-2010:')
for name, iso3, min_val in results:
    vals = {y: countries[iso3]['years'][y] for y in required_years}
    print(f'{name} ({iso3}): min={min_val:.2f}, values: {vals}')
"
